import React from 'react';
import { Warehouse, ArrowRight } from 'lucide-react';

const ManageStock = () => {
  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">Manage Stock</h2>
      <div className="p-12 bg-gradient-to-br from-blue-50 to-indigo-50 border-2 border-dashed border-blue-300 rounded-xl text-center">
        <Warehouse className="w-16 h-16 text-blue-400 mx-auto mb-4" />
        <h3 className="text-xl font-semibold text-gray-900 mb-2">Coming Soon</h3>
        <p className="text-gray-600 mb-6">Stock management features are being developed</p>
        <a href="/admin/inventory-alerts" className="inline-flex items-center gap-2 px-4 py-2 bg-blue-500 text-white rounded-lg hover:bg-blue-600 transition-colors">
          <ArrowRight className="w-4 h-4" />
          View Inventory Alerts
        </a>
      </div>
    </div>
  );
};

export default ManageStock;
